mapper.update:
UPDATE com.tn_atrz_prcs
   SET atrz_rslt_cd     = #{atrzRsltCd},
       atrz_dt          = NOW(),
       atrz_opnn        = #{atrzOpnn},
       last_chg_dt      = NOW(),
       last_chg_user_id = #{userId}
 WHERE atrz_dmnd_id = #{atrzDmndId}
   AND atrz_seq     = #{atrzSeq}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt

mapper.select:
SELECT COUNT(1)
  FROM com.tn_atrz_prcs
 WHERE atrz_dmnd_id = #{atrzDmndId}
   AND atrz_seq     < #{atrzSeq}
   AND atrz_rslt_cd IS NULL
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt
